const input = $json.body || $json;
const message = String(input.message || '').toLowerCase();

// STUDENT EDIT AREA:
// Add or change canned replies below.
const replies = [
  {
    keywords: ['refund', 'החזר', 'כסף'],
    intent: 'refund',
    answer: 'אפשר לבקש החזר עד 14 יום ממועד הרכישה. נציג יחזור אליך עם אישור.'
  },
  {
    keywords: ['shipping', 'delivery', 'משלוח', 'אספקה'],
    intent: 'shipping',
    answer: 'זמן משלוח רגיל הוא 3 עד 5 ימי עסקים. אפשר לבדוק סטטוס לפי מספר הזמנה.'
  },
  {
    keywords: ['price', 'cost', 'מחיר', 'עלות'],
    intent: 'pricing',
    answer: 'המחיר תלוי במסלול. אפשר להשאיר פרטים ונציג יתאים הצעה.'
  },
  {
    keywords: ['human', 'agent', 'נציג', 'אדם'],
    intent: 'human_agent',
    answer: 'אני מעביר את הפנייה לנציג שירות אנושי. זמן תגובה משוער: עד שעה.'
  }
];

const match = replies.find((reply) => reply.keywords.some((keyword) => message.includes(keyword)));
const selected = match || {
  intent: 'general',
  answer: 'תודה על הפנייה. חסרים לי פרטים כדי לענות במדויק. אפשר לציין מספר הזמנה או נושא?'
};

return [{
  json: {
    customer_name: input.name || 'לקוח/ה',
    original_message: input.message || '',
    detected_intent: selected.intent,
    reply: selected.answer,
    demo_note: 'תשובה מובנית לדמו בלבד',
    next_student_task: 'נסו להוסיף מילת מפתח ותשובה חדשה באזור העריכה.'
  }
}];
